mapper.select:
SELECT jeb.JOB_EXECUTION_ID, mb.base_cd, mb.base_name, bji.JOB_NAME as batch_name, bje.START_TIME as start_time, bje.END_TIME as end_time, bje.STATUS as status, COALESCE(bjed.error_message, bje.exit_message, bje.exit_code) AS errorMessage FROM job_execution_base jeb INNER JOIN BATCH_JOB_EXECUTION bje ON jeb.job_execution_id = bje.JOB_EXECUTION_ID INNER JOIN BATCH_JOB_INSTANCE bji ON bje.job_instance_id = bji.job_instance_id LEFT OUTER JOIN batch_job_import_error_deital bjed ON bje.job_execution_id = bjed.job_execution_id INNER JOIN master_base mb ON jeb.base_cd = mb.base_cd INNER JOIN registration_step RS ON mb.id = RS.identification_id AND RS.registration_status IN ('5', '6', '7') WHERE 1 = 0
OR mb.base_cd = #{param.base}
OR ( mb.base_cd LIKE CONCAT('%', #{param.base}, '%') OR mb.base_name LIKE CONCAT('%', #{param.base}, '%') )
OR bji.JOB_NAME = #{param.batch}
OR bji.JOB_NAME LIKE CONCAT('%', #{param.batch}, '%')
OR DATE(bje.START_TIME) = #{param.startDate}
ORDER BY
mb.base_cd ASC, bje.start_time DESC
bje.start_time ${param.sortOrder}
bje.end_time ${param.sortOrder}
mb.base_cd ${param.sortOrder}
mb.base_name ${param.sortOrder}
bji.JOB_NAME ${param.sortOrder}
mb.base_cd ASC, bje.start_time DESC
